+                    effect_id: "e-internal".into(),
+                    origin: TrafficOrigin::NodeInternal {
+                        subsystem: "control_plane".into(),
+                    },
+                    target_host: "localhost".into(),
+                    target_port: 9090,
+                    method: "GET".into(),
+                    path: "/internal/sync".into(),
